import asyncio
import websockets
import json
import uuid
from typing import Dict, Set, Optional
from dataclasses import dataclass, asdict
from enum import Enum
import logging

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)


class MessageType(Enum):
    LOGIN = "login"
    INVENTORY = "inventory"
    TRADE_REQUEST = "trade_request"
    TRADE_ACCEPT = "trade_accept"
    TRADE_CANCEL = "trade_cancel"
    TRADE_CONFIRM = "trade_confirm"
    TRADE_FINALIZE = "trade_finalize"
    ERROR = "error"
    SUCCESS = "success"


@dataclass
class Item:
    item_id: str
    name: str
    quantity: int
    
    def to_dict(self):
        return asdict(self)


@dataclass
class TradeOffer:
    items: Dict[str, int]  # item_id -> quantity
    
    def to_dict(self):
        return {"items": self.items}


class TradeState(Enum):
    PENDING = "pending"
    ACCEPTED = "accepted"
    CONFIRMED = "confirmed"
    COMPLETED = "completed"
    CANCELLED = "cancelled"


class Trade:
    def __init__(self, trade_id: str, player1_id: str, player2_id: str):
        self.trade_id = trade_id
        self.player1_id = player1_id
        self.player2_id = player2_id
        self.player1_offer: Optional[TradeOffer] = None
        self.player2_offer: Optional[TradeOffer] = None
        self.player1_confirmed = False
        self.player2_confirmed = False
        self.state = TradeState.PENDING
        self.lock = asyncio.Lock()
        
    def get_other_player(self, player_id: str) -> str:
        return self.player2_id if player_id == self.player1_id else self.player1_id
    
    def set_offer(self, player_id: str, offer: TradeOffer):
        if player_id == self.player1_id:
            self.player1_offer = offer
            self.player1_confirmed = False
        else:
            self.player2_offer = offer
            self.player2_confirmed = False
    
    def confirm_trade(self, player_id: str) -> bool:
        if player_id == self.player1_id:
            self.player1_confirmed = True
        else:
            self.player2_confirmed = True
        return self.player1_confirmed and self.player2_confirmed


class Player:
    def __init__(self, player_id: str, username: str):
        self.player_id = player_id
        self.username = username
        self.inventory: Dict[str, Item] = {}
        self.websocket: Optional[websockets.WebSocketServerProtocol] = None
        self.current_trade_id: Optional[str] = None
        self.lock = asyncio.Lock()
        
    def add_item(self, item: Item):
        if item.item_id in self.inventory:
            self.inventory[item.item_id].quantity += item.quantity
        else:
            self.inventory[item.item_id] = item
    
    def remove_item(self, item_id: str, quantity: int) -> bool:
        if item_id not in self.inventory:
            return False
        if self.inventory[item_id].quantity < quantity:
            return False
        self.inventory[item_id].quantity -= quantity
        if self.inventory[item_id].quantity == 0:
            del self.inventory[item_id]
        return True
    
    def has_items(self, items: Dict[str, int]) -> bool:
        for item_id, quantity in items.items():
            if item_id not in self.inventory:
                return False
            if self.inventory[item_id].quantity < quantity:
                return False
        return True
    
    def get_inventory_dict(self):
        return {item_id: item.to_dict() for item_id, item in self.inventory.items()}


class GameServer:
    def __init__(self):
        self.players: Dict[str, Player] = {}
        self.active_trades: Dict[str, Trade] = {}
        self.websocket_to_player: Dict[websockets.WebSocketServerProtocol, str] = {}
        self.server_lock = asyncio.Lock()
        
    def create_player(self, username: str) -> Player:
        player_id = str(uuid.uuid4())
        player = Player(player_id, username)
        
        # Initialize with some items
        player.add_item(Item(str(uuid.uuid4()), "Sword", 1))
        player.add_item(Item(str(uuid.uuid4()), "Gold Coin", 100))
        player.add_item(Item(str(uuid.uuid4()), "Health Potion", 5))
        
        self.players[player_id] = player
        return player
    
    async def handle_login(self, websocket, data):
        username = data.get("username", "Anonymous")
        player = self.create_player(username)
        player.websocket = websocket
        self.websocket_to_player[websocket] = player.player_id
        
        await self.send_message(websocket, MessageType.SUCCESS, {
            "action": "login",
            "player_id": player.player_id,
            "username": player.username,
            "inventory": player.get_inventory_dict()
        })
        logger.info(f"Player {username} logged in with ID {player.player_id}")
    
    async def handle_inventory(self, websocket, data):
        player_id = self.websocket_to_player.get(websocket)
        if not player_id:
            await self.send_error(websocket, "Not logged in")
            return
        
        player = self.players[player_id]
        await self.send_message(websocket, MessageType.INVENTORY, {
            "inventory": player.get_inventory_dict()
        })
    
    async def handle_trade_request(self, websocket, data):
        player_id = self.websocket_to_player.get(websocket)
        if not player_id:
            await self.send_error(websocket, "Not logged in")
            return
        
        target_player_id = data.get("target_player_id")
        if not target_player_id or target_player_id not in self.players:
            await self.send_error(websocket, "Invalid target player")
            return
        
        player = self.players[player_id]
        target_player = self.players[target_player_id]
        
        if player.current_trade_id:
            await self.send_error(websocket, "Already in a trade")
            return
        
        if target_player.current_trade_id:
            await self.send_error(websocket, "Target player is already in a trade")
            return
        
        trade_id = str(uuid.uuid4())
        trade = Trade(trade_id, player_id, target_player_id)
        
        async with self.server_lock:
            self.active_trades[trade_id] = trade
            player.current_trade_id = trade_id
            target_player.current_trade_id = trade_id
        
        await self.send_message(websocket, MessageType.SUCCESS, {
            "action": "trade_request",
            "trade_id": trade_id,
            "target_player": target_player.username
        })
        
        if target_player.websocket:
            await self.send_message(target_player.websocket, MessageType.TRADE_REQUEST, {
                "trade_id": trade_id,
                "from_player": player.username,
                "from_player_id": player_id
            })
        
        logger.info(f"Trade {trade_id} initiated between {player.username} and {target_player.username}")
    
    async def handle_trade_accept(self, websocket, data):
        player_id = self.websocket_to_player.get(websocket)
        if not player_id:
            await self.send_error(websocket, "Not logged in")
            return
        
        trade_id = data.get("trade_id")
        offered_items = data.get("items", {})
        
        if not trade_id or trade_id not in self.active_trades:
            await self.send_error(websocket, "Invalid trade")
            return
        
        trade = self.active_trades[trade_id]
        player = self.players[player_id]
        
        async with trade.lock:
            if trade.state != TradeState.PENDING and trade.state != TradeState.ACCEPTED:
                await self.send_error(websocket, "Trade is not in valid state")
                return
            
            async with player.lock:
                if not player.has_items(offered_items):
                    await self.send_error(websocket, "Insufficient items")
                    return
                
                offer = TradeOffer(offered_items)
                trade.set_offer(player_id, offer)
                trade.state = TradeState.ACCEPTED
        
        other_player_id = trade.get_other_player(player_id)
        other_player = self.players[other_player_id]
        
        await self.send_message(websocket, MessageType.SUCCESS, {
            "action": "trade_accept",
            "trade_id": trade_id,
            "your_offer": offered_items
        })
        
        if other_player.websocket:
            await self.send_message(other_player.websocket, MessageType.TRADE_ACCEPT, {
                "trade_id": trade_id,
                "other_player_offer": offered_items
            })
        
        logger.info(f"Player {player.username} accepted trade {trade_id} with offer: {offered_items}")
    
    async def handle_trade_confirm(self, websocket, data):
        player_id = self.websocket_to_player.get(websocket)
        if not player_id:
            await self.send_error(websocket, "Not logged in")
            return
        
        trade_id = data.get("trade_id")
        
        if not trade_id or trade_id not in self.active_trades:
            await self.send_error(websocket, "Invalid trade")
            return
        
        trade = self.active_trades[trade_id]
        
        async with trade.lock:
            if trade.state != TradeState.ACCEPTED:
                await self.send_error(websocket, "Trade not ready for confirmation")
                return
            
            if not trade.player1_offer or not trade.player2_offer:
                await self.send_error(websocket, "Both players must submit offers")
                return
            
            both_confirmed = trade.confirm_trade(player_id)
            
            if both_confirmed:
                trade.state = TradeState.CONFIRMED
                await self.finalize_trade(trade)
            else:
                other_player_id = trade.get_other_player(player_id)
                other_player = self.players[other_player_id]
                
                await self.send_message(websocket, MessageType.SUCCESS, {
                    "action": "trade_confirm",
                    "trade_id": trade_id,
                    "status": "waiting_for_other_player"
                })
                
                if other_player.websocket:
                    await self.send_message(other_player.websocket, MessageType.TRADE_CONFIRM, {
                        "trade_id": trade_id,
                        "status": "other_player_confirmed"
                    })
    
    async def finalize_trade(self, trade: Trade):
        player1 = self.players[trade.player1_id]
        player2 = self.players[trade.player2_id]
        
        async with player1.lock:
            async with player2.lock:
                # Verify both players still have the items
                if not player1.has_items(trade.player1_offer.items):
                    await self.cancel_trade(trade, "Player 1 no longer has offered items")
                    return
                
                if not player2.has_items(trade.player2_offer.items):
                    await self.cancel_trade(trade, "Player 2 no longer has offered items")
                    return
                
                # Remove items from both players
                for item_id, quantity in trade.player1_offer.items.items():
                    player1.remove_item(item_id, quantity)
                
                for item_id, quantity in trade.player2_offer.items.items():
                    player2.remove_item(item_id, quantity)
                
                # Add items to both players
                for item_id, quantity in trade.player1_offer.items.items():
                    original_item = None
                    for p_item in list(player1.inventory.values()) + list(player2.inventory.values()):
                        if p_item.item_id == item_id:
                            original_item = p_item
                            break
                    
                    if original_item:
                        player2.add_item(Item(item_id, original_item.name, quantity))
                
                for item_id, quantity in trade.player2_offer.items.items():
                    original_item = None
                    for p_item in list(player1.inventory.values()) + list(player2.inventory.values()):
                        if p_item.item_id == item_id:
                            original_item = p_item
                            break
                    
                    if original_item:
                        player1.add_item(Item(item_id, original_item.name, quantity))
        
        trade.state = TradeState.COMPLETED
        
        # Notify both players
        if player1.websocket:
            await self.send_message(player1.websocket, MessageType.SUCCESS, {
                "action": "trade_complete",
                "trade_id": trade.trade_id,
                "inventory": player1.get_inventory_dict()
            })
        
        if player2.websocket:
            await self.send_message(player2.websocket, MessageType.SUCCESS, {
                "action": "trade_complete",
                "trade_id": trade.trade_id,
                "inventory": player2.get_inventory_dict()
            })
        
        # Clean up
        async with self.server_lock:
            player1.current_trade_id = None
            player2.current_trade_id = None
            del self.active_trades[trade.trade_id]
        
        logger.info(f"Trade {trade.trade_id} completed successfully")
    
    async def cancel_trade(self, trade: Trade, reason: str):
        trade.state = TradeState.CANCELLED
        
        player1 = self.players[trade.player1_id]
        player2 = self.players[trade.player2_id]
        
        if player1.websocket:
            await self.send_message(player1.websocket, MessageType.ERROR, {
                "action": "trade_cancelled",
                "trade_id": trade.trade_id,
                "reason": reason
            })
        
        if player2.websocket:
            await self.send_message(player2.websocket, MessageType.ERROR, {
                "action": "trade_cancelled",
                "trade_id": trade.trade_id,
                "reason": reason
            })
        
        async with self.server_lock:
            player1.current_trade_id = None
            player2.current_trade_id = None
            if trade.trade_id in self.active_trades:
                del self.active_trades[trade.trade_id]
        
        logger.info(f"Trade {trade.trade_id} cancelled: {reason}")
    
    async def handle_trade_cancel(self, websocket, data):
        player_id = self.websocket_to_player.get(websocket)
        if not player_id:
            await self.send_error(websocket, "Not logged in")
            return
        
        trade_id = data.get("trade_id")
        
        if not trade_id or trade_id not in self.active_trades:
            await self.send_error(websocket, "Invalid trade")
            return
        
        trade = self.active_trades[trade_id]
        await self.cancel_trade(trade, "Cancelled by player")
    
    async def send_message(self, websocket, msg_type: MessageType, data: dict):
        message = {
            "type": msg_type.value,
            "data": data
        }
        await websocket.send(json.dumps(message))
    
    async def send_error(self, websocket, error: str):
        await self.send_message(websocket, MessageType.ERROR, {"error": error})
    
    async def handle_client(self, websocket, path):
        try:
            async for message in websocket:
                try:
                    data = json.loads(message)
                    msg_type = data.get("type")
                    msg_data = data.get("data", {})
                    
                    if msg_type == MessageType.LOGIN.value:
                        await self.handle_login(websocket, msg_data)
                    elif msg_type == MessageType.INVENTORY.value:
                        await self.handle_inventory(websocket, msg_data)
                    elif msg_type == MessageType.TRADE_REQUEST.value:
                        await self.handle_trade_request(websocket, msg_data)
                    elif msg_type == MessageType.TRADE_ACCEPT.value:
                        await self.handle_trade_accept(websocket, msg_data)
                    elif msg_type == MessageType.TRADE_CONFIRM.value:
                        await self.handle_trade_confirm(websocket, msg_data)
                    elif msg_type == MessageType.TRADE_CANCEL.value:
                        await self.handle_trade_cancel(websocket, msg_data)
                    else:
                        await self.send_error(websocket, "Unknown message type")
                
                except json.JSONDecodeError:
                    await self.send_error(websocket, "Invalid JSON")
                except Exception as e:
                    logger.error(f"Error handling message: {e}")
                    await self.send_error(websocket, str(e))
        
        finally:
            # Clean up on disconnect
            if websocket in self.websocket_to_player:
                player_id = self.websocket_to_player[websocket]
                player = self.players.get(player_id)
                
                if player and player.current_trade_id:
                    trade = self.active_trades.get(player.current_trade_id)
                    if trade:
                        await self.cancel_trade(trade, "Player disconnected")
                
                del self.websocket_to_player[websocket]
                logger.info(f"Player {player_id} disconnected")
    
    async def start(self, host="localhost", port=8765):
        async with websockets.serve(self.handle_client, host, port):
            logger.info(f"Game server started on ws://{host}:{port}")
            await asyncio.Future()


